import re
from datetime import date


def parse_iso_calendar_date(value: str) -> date:
    if not isinstance(value, str) or re.fullmatch(r"\d{4}-\d{2}-\d{2}", value) is None:
        raise ValueError("value must use YYYY-MM-DD")
    try:
        return date.fromisoformat(value)
    except ValueError as exc:
        raise ValueError("value must be a valid calendar date") from exc

def require_trimmed_string_list(value: object) -> list[str]:
    if not isinstance(value, list):
        raise TypeError("value must be a list")

    result: list[str] = []
    for index, item in enumerate(value):
        if not isinstance(item, str):
            raise TypeError(f"item {index} must be a string")
        cleaned = item.strip()
        if not cleaned:
            raise ValueError(f"item {index} must not be blank")
        result.append(cleaned)
    return result

def parse_assignment(line: str) -> tuple[str, str]:
    if not isinstance(line, str):
        raise TypeError("line must be a string")
    if "=" not in line:
        raise ValueError("assignment must contain =")

    key, value = line.split("=", 1)
    key = key.strip()
    if not key:
        raise ValueError("assignment key must not be blank")
    return key, value.strip()

import re


def parse_hex_color(value: str) -> tuple[int, int, int]:
    if not isinstance(value, str) or re.fullmatch(r"#[0-9A-Fa-f]{6}", value) is None:
        raise ValueError("color must be # followed by six hexadecimal digits")
    return tuple(int(value[index:index + 2], 16) for index in (1, 3, 5))

def sum_nonnegative_cents(values: list[object]) -> int:
    total = 0
    for index, value in enumerate(values):
        if isinstance(value, bool) or not isinstance(value, int):
            raise TypeError(f"item {index} must be an integer")
        if value < 0:
            raise ValueError(f"item {index} must be non-negative")
        total += value
    return total

import re


def require_snake_identifier(value: str) -> str:
    if not isinstance(value, str):
        raise TypeError("value must be a string")
    if re.fullmatch(r"[a-z](?:[a-z0-9]|_(?=[a-z0-9]))*", value) is None:
        raise ValueError("value must be a canonical snake identifier")
    return value

def merge_nonnegative_counts(
    left: dict[str, int], right: dict[str, int]
) -> dict[str, int]:
    def checked(mapping: dict[str, int], name: str) -> None:
        for key, count in mapping.items():
            if not isinstance(key, str) or not key.strip():
                raise ValueError(f"{name} contains an invalid key")
            if isinstance(count, bool) or not isinstance(count, int):
                raise TypeError(f"count for {key!r} must be an integer")
            if count < 0:
                raise ValueError(f"count for {key!r} must be non-negative")

    checked(left, "left")
    checked(right, "right")
    result = dict(left)
    for key, count in right.items():
        result[key] = result.get(key, 0) + count
    return result

import re


def parse_decimal_cents(value: str) -> int:
    if not isinstance(value, str):
        raise TypeError("value must be a string")
    match = re.fullmatch(r"(0|[1-9]\d*)(?:\.(\d{2}))?", value)
    if match is None:
        raise ValueError("value must be canonical non-negative decimal money")
    whole, fraction = match.groups()
    return int(whole) * 100 + int(fraction or "00")

def transpose_rectangular(rows: list[list[int]]) -> list[list[int]]:
    if not rows:
        return []
    width = len(rows[0])
    if any(len(row) != width for row in rows):
        raise ValueError("rows must form a rectangular matrix")
    return [[row[column] for row in rows] for column in range(width)]

from urllib.parse import urlencode


def build_query_string(params: dict[str, str]) -> str:
    items: list[tuple[str, str]] = []
    for key, value in params.items():
        if not isinstance(key, str) or not key.strip():
            raise ValueError("query keys must be non-blank strings")
        if not isinstance(value, str):
            raise TypeError(f"query value for {key!r} must be a string")
        items.append((key, value))

    items.sort(key=lambda item: item[0])
    return urlencode(items)

def make_rows(count: int) -> list[list[str]]:
