def select_columns(
    rows: list[dict[str, object]], columns: list[str]
) -> list[dict[str, object]]:
    if any(not isinstance(column, str) or not column.strip() for column in columns):
        raise ValueError("columns must contain non-blank strings")
    if len(set(columns)) != len(columns):
        raise ValueError("columns must be unique")

    result: list[dict[str, object]] = []
    for row_index, row in enumerate(rows):
        selected: dict[str, object] = {}
        for column in columns:
            if column not in row:
                raise ValueError(f"row {row_index} is missing column {column!r}")
            selected[column] = row[column]
        result.append(selected)
    return result

function requireTrimmedStringArray(value: unknown): string[] {
