function requireEnumMember<const T extends readonly string[]>(
  value: unknown,
  allowed: T,
): T[number] {
  if (typeof value !== "string" || !allowed.includes(value)) {
    throw new Error(`value must be one of: ${allowed.join(", ")}`);
  }
  return value as T[number];
}

function parseUtcOffset(value: unknown): number {
  if (value === "Z") return 0;
  if (typeof value !== "string") {
    throw new TypeError("offset must be a string");
  }
  const match = /^([+-])(\d{2}):(\d{2})$/.exec(value);
  if (!match) {
    throw new Error("offset must be Z or sign followed by HH:MM");
  }
  const hours = Number(match[2]);
  const minutes = Number(match[3]);
  if (hours > 14 || minutes > 59 || (hours === 14 && minutes !== 0)) {
    throw new Error("offset is outside the supported range");
  }
  const total = hours * 60 + minutes;
  return match[1] === "-" ? -total : total;
}

function requireRgbTuple(value: unknown): readonly [number, number, number] {
  if (!Array.isArray(value) || value.length !== 3) {
    throw new Error("RGB value must contain exactly three items");
  }
  const checked = value.map((item, index) => {
    if (!Number.isInteger(item) || item < 0 || item > 255) {
      throw new Error(`RGB item ${index} must be an integer from 0 to 255`);
    }
    return item;
  });
  return [checked[0], checked[1], checked[2]];
}

function parseCoreSemver(
  value: unknown,
): { major: number; minor: number; patch: number } {
  if (typeof value !== "string") {
    throw new TypeError("version must be a string");
  }
  const match = /^(0|[1-9]\d*)\.(0|[1-9]\d*)\.(0|[1-9]\d*)$/.exec(value);
  if (!match) {
    throw new Error("version must be canonical major.minor.patch");
  }
  const [major, minor, patch] = match.slice(1).map(Number);
  if (![major, minor, patch].every(Number.isSafeInteger)) {
    throw new Error("version component exceeds the safe integer range");
  }
  return { major, minor, patch };
}

function cumulativeFiniteTotals(values: readonly number[]): number[] {
  const result: number[] = [];
  let total = 0;
  for (const [index, value] of values.entries()) {
    if (!Number.isFinite(value)) {
      throw new Error(`item ${index} must be finite`);
    }
    total += value;
    if (!Number.isFinite(total)) {
      throw new Error(`running total at item ${index} is not finite`);
    }
    result.push(total);
  }
  return result;
}

