function mapUniqueNames(
  items: readonly { name: string; value: number }[],
): Map<string, number> {
  const result = new Map<string, number>();
  for (const [index, item] of items.entries()) {
    const name = item.name.trim();
    if (name.length === 0) {
      throw new Error(`item ${index} has a blank name`);
    }
    if (!Number.isFinite(item.value)) {
      throw new Error(`item ${index} has a non-finite value`);
    }
    if (result.has(name)) {
      throw new Error(`duplicate name: ${name}`);
    }
    result.set(name, item.value);
  }
  return result;
}

