function sumLineTotals(lines) {
  if (!Array.isArray(lines)) {
    throw new TypeError("lines must be an array");
  }
  let total = 0;
  lines.forEach((line, index) => {
    if (line === null || typeof line !== "object") {
      throw new TypeError(`line ${index} must be an object`);
    }
    const { quantity, unitCents } = line;
    if (!Number.isSafeInteger(quantity) || quantity < 0) {
      throw new Error(`line ${index} quantity must be a non-negative safe integer`);
    }
    if (!Number.isSafeInteger(unitCents) || unitCents < 0) {
      throw new Error(`line ${index} unitCents must be a non-negative safe integer`);
    }
    const lineTotal = quantity * unitCents;
    if (!Number.isSafeInteger(lineTotal) || !Number.isSafeInteger(total + lineTotal)) {
      throw new Error("total exceeds the safe integer range");
    }
    total += lineTotal;
  });
  return total;
}

function parseSortDirection(value, fallback = "asc") {
  const allowed = new Set(["asc", "desc"]);
  if (!allowed.has(fallback)) {
    throw new Error("fallback must be asc or desc");
  }
  const selected = value === undefined ? fallback : value;
  if (!allowed.has(selected)) {
    throw new Error("sort direction must be asc or desc");
  }
  return selected;
}

