function normalizeLabelMap(entries) {
  if (!Array.isArray(entries)) {
    throw new TypeError("entries must be an array");
  }
  const result = Object.create(null);
  entries.forEach((entry, index) => {
    if (!Array.isArray(entry) || entry.length !== 2) {
      throw new Error(`entry ${index} must contain [label, value]`);
    }
    const [rawLabel, value] = entry;
    if (typeof rawLabel !== "string") {
      throw new TypeError(`entry ${index} label must be a string`);
    }
    const label = rawLabel.trim().toLowerCase();
    if (label.length === 0) {
      throw new Error(`entry ${index} label must not be blank`);
    }
    if (Object.hasOwn(result, label)) {
      throw new Error(`duplicate normalized label: ${label}`);
    }
    result[label] = value;
  });
  return result;
}

